# Packer: bake an immutable AMI with all patches applied
source "amazon-ebs" "app" {
  source_ami_filter {
    filters = { name = "ubuntu/images/hvm-ssd/ubuntu-22.04-*" }
    most_recent = true
  }
  instance_type = "t3.micro"
}

build {
  sources = ["source.amazon-ebs.app"]
  provisioner "shell" {
    script = "scripts/provision.sh"  # installs app, patches OS
  }
}
